// 1. Récupération de la réponse IA
const raw = $json.output || "";
let cleanRaw = raw.replace(/```json/gi, "").replace(/```/g, "").trim();
const start = cleanRaw.indexOf("{");
const end = cleanRaw.lastIndexOf("}");

if (start === -1) throw new Error("No JSON found in AI output");

let stringToParse = cleanRaw.slice(start, end + 1);
let aiData = {};

try {
    // TENTATIVE 1 : Le JSON est parfait, on le lit normalement.
    aiData = JSON.parse(stringToParse);
} catch (e1) {
    try {
        // TENTATIVE 2 : Le Nettoyeur. On répare les erreurs IA courantes.
        // On enlève les virgules traînantes (ex: "tags": ["a",],)
        let fixedString = stringToParse.replace(/,\s*([\]}])/g, '$1');
        // On échappe les retours à la ligne qui cassent les chaînes de caractères
        fixedString = fixedString.replace(/\n/g, "\\n").replace(/\r/g, "\\r");

        aiData = JSON.parse(fixedString);
    } catch (e2) {
        // TENTATIVE 3 : Le Mode Hache (Regex). On sauve le produit coûte que coûte !
        // Si la structure JSON est morte, on va chercher les infos avec des pinces.
        const extract = (regex, defaultVal) => {
            const match = stringToParse.match(regex);
            return match ? match[1] : defaultVal;
        };

        aiData = {
            // Si on trouve "should_publish": true, on publie. Sinon, par sécurité on met true pour ne pas perdre le produit.
            should_publish: /"should_publish"\s*:\s*true/i.test(stringToParse),
            category_slug: extract(/"category_slug"\s*:\s*"([^"]+)"/, "autres"),
            product: {
                title: extract(/"title"\s*:\s*"([^"]+)"/, "Titre à revoir"),
                slug: extract(/"slug"\s*:\s*"([^"]+)"/, "produit-a-verifier"),
                // On arrache la description en prenant tout ce qui est entre "description": " et le champ suivant "brand"
                description: extract(/"description"\s*:\s*"([\s\S]*?)"\s*,\s*"brand"/, "Description générée mais mal formatée. À vérifier en base."),
                brand: extract(/"brand"\s*:\s*"([^"]+)"/, "Générique"),
                tags: []
            },
            variant_translations: {} // On sacrifie juste les traductions de couleurs pour sauver l'essentiel
        };
    }
}

// 2. Récupération des données SOURCE FIABLES (CJ Details)
const detailNode = $node["[CJ]_Get_Enrich_Product_Details"];
if (!detailNode || !detailNode.json || !detailNode.json.data) {
    throw new Error("Source CJ Details introuvable !");
}
const cjData = detailNode.json.data;
const cjVariants = cjData.variants || [];

// 3. MAPPING DES CATÉGORIES
const categoryMap = {
    'coques-protections': 1, 'charge-energie': 2, 'audio-son': 3,
    'supports-fixations': 4, 'decoration-goodies': 5, 'autres': 6
};

// 4. CONSTRUCTION INTELLIGENTE DES VARIANTES
const aiTranslations = aiData.variant_translations || {};

const cleanVariants = cjVariants.map(v => {
    const originalName = v.variantNameEn || v.variantName || "";
    let cleanName = aiTranslations[originalName] || originalName;

    if (cleanName === originalName) {
        cleanName = cleanName.replace(/Apple/ig, "").replace(/Phone Case/ig, "").trim();
    }

    return {
        vid: String(v.vid),
        sku: String(v.variantSku),
        name: cleanName,
        price: parseFloat(v.variantSellPrice)
    };
});

// 5. OBJET FINAL (Sauvé et prêt à l'export)
const merged = {
    should_publish: aiData.should_publish !== undefined ? aiData.should_publish : true,
    pid: String(cjData.pid),

    title: (aiData.product?.title || cjData.productNameEn || "Produit") + " (" + String(cjData.pid) + ")",
    slug: (aiData.product?.slug || "produit") + "-" + String(cjData.pid),
    description: aiData.product?.description || "Aucune description.",
    brand: aiData.product?.brand || "Autres",
    tags: aiData.product?.tags || [],

    images: cjData.productImageSet || [],
    variants: cleanVariants,

    nc_category_id: categoryMap[aiData.category_slug] || 6,
    base_price: cjData.sellPrice,
    ai_quality_notes: aiData.quality_notes || "Sauvetage automatique : l'IA a fait une erreur de syntaxe."
};

return { json: merged };

const p = $json;

// --- 1. LA CARTE AU TRÉSOR (UUIDs NocoDB) ---
const CATEGORY_UUIDS = {
  1: "3e40840a-5111-44ef-b264-a75b836b9138", // Coques & protections
  2: "81c1a551-4ce4-40f7-a096-e85fc9f74a71", // Charge & énergie
  3: "64900192-a354-41c1-8f35-a1d13299352e", // Audio & son
  4: "46484275-e161-4bef-8a71-f67d51cb639f", // Supports & fixations
  5: "2070f06d-c3e0-4253-947d-374f8f46368a", // Décoration & goodies
  6: "7167a98a-60dd-4f78-9a56-e206813d4a3c"  // Autres
};

// --- 2. SÉCURISATION & CALCULS ---
const safePrice = parseFloat(p.base_price) || 0;
const aiCategoryNumber = parseInt(p.nc_category_id);
const finalCategoryUUID = CATEGORY_UUIDS[aiCategoryNumber] || CATEGORY_UUIDS[6];

const mainImage = (Array.isArray(p.images) && p.images.length > 0) ? p.images[0] : null;
const tagsArray = Array.isArray(p.tags) ? p.tags : [];
const imagesArray = Array.isArray(p.images) ? p.images : [];

// --- 3. CRÉATION DU PAQUET ---
return [
  {
    json: {
      title: String(p.title || "").substring(0, 255),
      slug: String(p.slug || ""),
      description: String(p.description || ""),
      base_price: safePrice,
      cj_pid: String(p.pid),
