      _VARIANTS_READY: (p.variants || []).map(v => ({
          cj_vid: String(v.vid),
          sku: String(v.sku),
          option1_name: "Modèle",
          option1_value: String(v.name),
          price: parseFloat(v.price) || safePrice
      }))
    }
  }
];

// [CJ] 13A - MAP - Prepare Variants
// Objectif : 1 item par variante avec champs utiles + FK produit + valeurs "factorized" robustes

// 1) ID du produit créé (node 13 en input direct)
const createdProduct = $input.first().json;
const productId = createdProduct.Id || createdProduct.id;

if (!productId) {
  throw new Error("Impossible de trouver l'ID du produit créé (Id/id manquant).");
}

// 2) Variantes préparées dans le node 12
const previousData = $node["[CJ] 12 - MAP - Build Product (Published Payload)"].json;
const variantsList = previousData._VARIANTS_READY || [];

// 3) Détails produit/variants (node API) -> 1 seul item, donc OK ici
const apiItem = $node["[CJ]_Get_Enrich_Product_Details"].json;
const details = apiItem?.data || {};
const detailsVariants = Array.isArray(details.variants) ? details.variants : [];
const productImageSet = Array.isArray(details.productImageSet) ? details.productImageSet : [];

function norm(s) {
  return String(s ?? "").replace(/\s+/g, " ").trim();
}

function rightWordSlice(raw, min = 20, max = 35) {
  const s = norm(raw);
  if (!s) return null;
  if (s.length <= max) return s;

  const delims = [" ", "-", "_", "/", "|"];

  const lastDelimBefore = (str, idx) => {
    let best = -1;
    for (const d of delims) {
      const p = str.lastIndexOf(d, idx);
      if (p > best) best = p;
    }
    return best;
  };

  const firstDelimAfter = (str, idx) => {
    for (let i = idx; i < str.length; i++) {
      if (delims.includes(str[i])) return i;
    }
    return -1;
  };

  // coupe à droite sur max, puis ajuste au prochain séparateur pour ne pas couper un mot
  let start = s.length - max;
  const next = firstDelimAfter(s, start);
  if (next !== -1 && (s.length - (next + 1)) >= min) start = next + 1;

  let out = s.slice(start).trim();

  // si trop court, on recule au séparateur précédent (peut dépasser max un peu, accepté)
  if (out.length < min) {
    const start2 = Math.max(0, s.length - min);
    const prev = lastDelimBefore(s, start2);
    if (prev !== -1) out = s.slice(prev + 1).trim();
    else out = s.slice(start2).trim();
  }

  return out || null;
}

function extractTailModel(raw) {
  const s = norm(raw);
  if (!s) return null;

  // 1) iPhone (inclut iPhone16E, iPhone15ProMax, XSmax, XR, X, SE, etc.)
  const rApple =
    /(?:\b(?:iPhone|IPhone|iphone)\b\s*)?(?:(?:\d{1,2}[A-Za-z]?)|(?:XS\s*Max|XSmax|XS|XR|Xr|X|SE|Se))(?:\s*(?:Pro\s*Max|ProMax|Promax|promax|Pro|PRO|Max|MAX|Plus|PLUS|mini|Mini|Air|AIR))?\s*$/;

  // 2) Samsung / Galaxy (générique)
  const rSamsung =
    /(?:\b(?:Samsung|SAMSUNG|samsung|Galaxy|GALAXY|galaxy)\b\s*)?(?:Note\s*)?(?:[SAMZ]\s*)?\d{1,2}(?:\s*(?:Ultra|ULTRA|Plus|PLUS|Pro|PRO|FE|Fe|Lite|LITE|Max|MAX))?\s*$/;

  const m1 = s.match(rApple);
  if (m1 && m1[0]) return m1[0].trim();

  const m2 = s.match(rSamsung);
  if (m2 && m2[0]) return m2[0].trim();

  // 3) fallback robuste (fin de chaîne 20–35 sans couper)
  return rightWordSlice(s, 20, 35);
}

function toNumber(v, fallback = null) {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

function computeStock(vDet) {
  if (!vDet) return 0;

  // CJ renvoie parfois inventoryNum ou un tableau inventories
  if (vDet.inventoryNum !== null && vDet.inventoryNum !== undefined) {
    return toNumber(vDet.inventoryNum, 0);
  }

  const invs = vDet.inventories;
  if (Array.isArray(invs)) {
    return invs.reduce((sum, i) => sum + (toNumber(i?.inventoryNum, 0) || 0), 0);
  }

  return 0;
}

// 4) Sortie : 1 ligne par variante
const mappedVariants = variantsList.map((variant) => {
  const vid = variant.cj_vid ?? variant.vid ?? null;

  // matching sur l'API (sécurisé)
  const vDet =
    detailsVariants.find((x) => String(x?.vid) === String(vid)) || null;

  // champs variant (priorité : ce que tu as déjà, sinon API)
  const imageUrl =
    variant.image_url ||
    variant.variant_image ||
    variant.variantImage ||
    vDet?.variantImage ||
    null;

  const weightGrams =
    variant.weight_grams ??
    vDet?.variantWeight ??
    null;

  const costPrice =
    variant.cost_price ??
    vDet?.variantSellPrice ??
    null;

  const sellPrice =
    variant.price ??
    vDet?.variantSugSellPrice ??
    vDet?.variantSellPrice ??
    null;

  const stockQty =
    variant.stock_quantity ??
    variant.stock ??
    computeStock(vDet);

  // factorized / compact (pour le front)
  const opt1 = variant.option1_value ?? null;
  const opt2 = variant.option2_value ?? null;

  const opt1Factorized = extractTailModel(opt1);
  const opt2Factorized = extractTailModel(opt2);

  return {
    json: {
      // Identifiants variante
